      "main.puf": "(require \"vec.puf\")\n(require \"table.puf\" #:as T)\n(require \"util.puf\" #:only (twice compose) #:rename ((twice do-twice)))\n(println (dot (list 1 2 3) (list 4 5 6)))\n(println (norm2 (list 3 4)))\n(println (T.size (list 1 2)))\n(println (T.lookup (list (cons 'a 1) (cons 'b 2)) 'b))\n(println (T.classify (list 'vec 7 8)))\n(println (do-twice (lambda (x) (* x x)) 3))\n(println ((compose (lambda (x) (+ x 1)) (lambda (x) (* x 10))) 4))\n;; own len wins over the module's un-imported one; prelude length intact\n(define (len l) 999)\n(println (len (list 1 2)))\n(println (length (list 1 2 3)))\n",
      "table.puf": ";; qualified-only import target; defines its own `length` (module-\n;; private shadow of the prelude) and matches on cross-module data\n(provide size lookup classify)\n(define (length l) 1000000)\n(define (size t) (length t))\n(define (lookup t k)\n  (match t\n    ['() #f]\n    [`((,k2 . ,v) . ,rest) (if (eq? k k2) v (lookup rest k))]))\n(define (classify v)\n  (match v\n    [`(vec ,xs ...) (cons 'vector-of xs)]\n    [(? number? n) 'num]\n    [_ 'other]))\n",
